/**
 * Generate Ahrefs firewall config.
 *
 * Data source: https://docs.ahrefs.com/docs/api/reference/introduction
 *
 * Ahrefs is an SEO toolset for backlink analysis and keyword research.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.ahrefs.com/docs/api/reference/introduction";
// Token format not publicly documented; using generic alphanumeric placeholder
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe00";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Ahrefs API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:ahrefs",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const ahrefsFirewall = {",
    '  name: "ahrefs",',
    '  description: "Ahrefs API",',
    "  placeholders: {",
    `    AHREFS_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.ahrefs.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.AHREFS_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Ahrefs firewall config...");
  const ts = generateTypeScript();
  writeOutput("ahrefs", ts, import.meta.dirname);
}
